import React, { useState } from "react";
import axios from "axios";

export default function Register() {
  const [user, setUser] = useState({
    firstName: "",
    lastName: "",
    gender: "",
    email: "",
    contactNo: "",
    role: "",
    empid: "",
    username: "",
    password: ""
  });

  const handleChange = (e) => {
    setUser({ ...user, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    try {
      const res = await axios.post("http://localhost:8080/register", user);
      alert(res.data); // shows "Registration successful"
    } catch (err) {
      console.error(err);
      alert("Registration Failed ❌");
    }
  };

  return (
    <div style={{ textAlign: "center", marginTop: "30px" }}>
      <h2>Register</h2>

      <form onSubmit={handleSubmit}>
        <input name="firstName" placeholder="First Name" onChange={handleChange} required /><br /><br />
        <input name="lastName" placeholder="Last Name" onChange={handleChange} required /><br /><br />

        <select name="gender" onChange={handleChange} required>
          <option value="">Select Gender</option>
          <option>Male</option>
          <option>Female</option>
        </select><br /><br />

        <input type="email" name="email" placeholder="Email" onChange={handleChange} required /><br /><br />
        <input type="number" name="contactNo" placeholder="Contact No" onChange={handleChange} required /><br /><br />

        <input name="role" placeholder="Role (admin/user)" onChange={handleChange} required /><br /><br />
        <input type="number" name="empid" placeholder="Employee ID" onChange={handleChange} /><br /><br />

        <input name="username" placeholder="Username" onChange={handleChange} required /><br /><br />
        <input type="password" name="password" placeholder="Password" onChange={handleChange} required /><br /><br />

        <button type="submit">Register</button>
      </form>
    </div>
  );
}
